import{_ as e,o as s,c as n,ag as t}from"./chunks/framework.CAXxHpAX.js";const h=JSON.parse('{"title":"自定义 GPU 指标","description":"Node Push Exporter 自定义 GPU 指标详解","frontmatter":{"title":"自定义 GPU 指标","description":"Node Push Exporter 自定义 GPU 指标详解"},"headers":[],"relativePath":"metrics/gpu.md","filePath":"metrics/gpu.md"}'),p={name:"metrics/gpu.md"};function o(d,a,r,i,l,c){return s(),n("div",null,[...a[0]||(a[0]=[t(`<h1 id="自定义-gpu-指标" tabindex="-1">自定义 GPU 指标 <a class="header-anchor" href="#自定义-gpu-指标" aria-label="Permalink to &quot;自定义 GPU 指标&quot;">​</a></h1><p>Node Push Exporter 通过调用 <code>nvidia-smi</code> 和 <code>rocm-smi</code> 采集额外的 GPU 指标，这些指标不包含在标准 node_exporter 中。</p><h2 id="指标采集状态" tabindex="-1">指标采集状态 <a class="header-anchor" href="#指标采集状态" aria-label="Permalink to &quot;指标采集状态&quot;">​</a></h2><h3 id="node-push-exporter-gpu-scrape-timestamp-seconds" tabindex="-1">node_push_exporter_gpu_scrape_timestamp_seconds <a class="header-anchor" href="#node-push-exporter-gpu-scrape-timestamp-seconds" aria-label="Permalink to &quot;node_push_exporter_gpu_scrape_timestamp_seconds&quot;">​</a></h3><p>GPU 指标采集时间戳。</p><p><strong>类型:</strong> Gauge</p><p><strong>标签:</strong> 无</p><h3 id="node-push-exporter-gpu-scrape-success" tabindex="-1">node_push_exporter_gpu_scrape_success <a class="header-anchor" href="#node-push-exporter-gpu-scrape-success" aria-label="Permalink to &quot;node_push_exporter_gpu_scrape_success&quot;">​</a></h3><p>GPU 指标采集是否成功。</p><p><strong>类型:</strong> Gauge</p><p><strong>标签:</strong> <code>vendor</code></p><table tabindex="0"><thead><tr><th>值</th><th>含义</th></tr></thead><tbody><tr><td>1</td><td>采集成功</td></tr><tr><td>0</td><td>采集失败</td></tr></tbody></table><h3 id="node-push-exporter-gpu-devices-detected" tabindex="-1">node_push_exporter_gpu_devices_detected <a class="header-anchor" href="#node-push-exporter-gpu-devices-detected" aria-label="Permalink to &quot;node_push_exporter_gpu_devices_detected&quot;">​</a></h3><p>检测到的 GPU 设备数量。</p><p><strong>类型:</strong> Gauge</p><p><strong>标签:</strong> <code>vendor</code></p><div class="language-promql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">promql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># 检查 GPU 是否被正确识别</span></span>
<span class="line"><span>node_push_exporter_gpu_devices_detected{job=&quot;node&quot;}</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 按厂商统计 GPU 数量</span></span>
<span class="line"><span>sum by (vendor) (node_push_exporter_gpu_devices_detected{job=&quot;node&quot;})</span></span></code></pre></div><h2 id="通用-gpu-指标" tabindex="-1">通用 GPU 指标 <a class="header-anchor" href="#通用-gpu-指标" aria-label="Permalink to &quot;通用 GPU 指标&quot;">​</a></h2><p>以下指标同时适用于 NVIDIA 和 AMD ROCm GPU：</p><h3 id="gpu-up" tabindex="-1">gpu_up <a class="header-anchor" href="#gpu-up" aria-label="Permalink to &quot;gpu_up&quot;">​</a></h3><p>GPU 设备是否在线。</p><p><strong>类型:</strong> Gauge</p><p><strong>标签:</strong> <code>vendor</code>, <code>gpu</code>, <code>name</code>, <code>uuid</code>, <code>device_id</code></p><table tabindex="0"><thead><tr><th>值</th><th>含义</th></tr></thead><tbody><tr><td>1</td><td>GPU 在线</td></tr><tr><td>0</td><td>GPU 离线</td></tr></tbody></table><h3 id="gpu-info" tabindex="-1">gpu_info <a class="header-anchor" href="#gpu-info" aria-label="Permalink to &quot;gpu_info&quot;">​</a></h3><p>GPU 设备信息（恒定为 1）。</p><p><strong>类型:</strong> Gauge</p><p><strong>标签:</strong> <code>vendor</code>, <code>gpu</code>, <code>name</code>, <code>uuid</code>, <code>device_id</code></p><p>用于在查询时获取 GPU 静态信息。</p><h2 id="温度指标" tabindex="-1">温度指标 <a class="header-anchor" href="#温度指标" aria-label="Permalink to &quot;温度指标&quot;">​</a></h2><h3 id="gpu-temperature-celsius" tabindex="-1">gpu_temperature_celsius <a class="header-anchor" href="#gpu-temperature-celsius" aria-label="Permalink to &quot;gpu_temperature_celsius&quot;">​</a></h3><p>GPU 核心温度。</p><p><strong>类型:</strong> Gauge</p><p><strong>标签:</strong> <code>vendor</code>, <code>gpu</code>, <code>name</code>, <code>uuid</code>, <code>device_id</code></p><div class="language-promql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">promql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># 获取所有 GPU 温度</span></span>
<span class="line"><span>gpu_temperature_celsius{job=&quot;node&quot;}</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 按实例统计平均温度</span></span>
<span class="line"><span>avg by (instance) (gpu_temperature_celsius{job=&quot;node&quot;})</span></span></code></pre></div><h3 id="gpu-temperature-edge-celsius" tabindex="-1">gpu_temperature_edge_celsius <a class="header-anchor" href="#gpu-temperature-edge-celsius" aria-label="Permalink to &quot;gpu_temperature_edge_celsius&quot;">​</a></h3><p>GPU Edge 温度传感器读数。</p><p><strong>类型:</strong> Gauge</p><p><strong>标签:</strong> 同上</p><h3 id="gpu-temperature-junction-celsius" tabindex="-1">gpu_temperature_junction_celsius <a class="header-anchor" href="#gpu-temperature-junction-celsius" aria-label="Permalink to &quot;gpu_temperature_junction_celsius&quot;">​</a></h3><p>GPU 结温（Junction Temperature）。</p><p><strong>类型:</strong> Gauge</p><p><strong>标签:</strong> 同上</p><h3 id="gpu-temperature-mem-celsius" tabindex="-1">gpu_temperature_mem_celsius <a class="header-anchor" href="#gpu-temperature-mem-celsius" aria-label="Permalink to &quot;gpu_temperature_mem_celsius&quot;">​</a></h3><p>GPU 显存温度。</p><p><strong>类型:</strong> Gauge</p><p><strong>标签:</strong> 同上</p><h3 id="gpu-temperature-core-celsius" tabindex="-1">gpu_temperature_core_celsius <a class="header-anchor" href="#gpu-temperature-core-celsius" aria-label="Permalink to &quot;gpu_temperature_core_celsius&quot;">​</a></h3><p>GPU 核心温度（备选传感器）。</p><p><strong>类型:</strong> Gauge</p><p><strong>标签:</strong> 同上</p><h3 id="温度告警阈值" tabindex="-1">温度告警阈值 <a class="header-anchor" href="#温度告警阈值" aria-label="Permalink to &quot;温度告警阈值&quot;">​</a></h3><table tabindex="0"><thead><tr><th>级别</th><th>阈值</th><th>建议操作</th></tr></thead><tbody><tr><td>正常</td><td>&lt; 70°C</td><td>无需处理</td></tr><tr><td>警告</td><td>70-85°C</td><td>监控频率增加</td></tr><tr><td>危险</td><td>&gt; 85°C</td><td>检查散热</td></tr><tr><td>临界</td><td>&gt; 95°C</td><td>可能触发降频保护</td></tr></tbody></table><h2 id="利用率指标" tabindex="-1">利用率指标 <a class="header-anchor" href="#利用率指标" aria-label="Permalink to &quot;利用率指标&quot;">​</a></h2><h3 id="gpu-utilization-percent" tabindex="-1">gpu_utilization_percent <a class="header-anchor" href="#gpu-utilization-percent" aria-label="Permalink to &quot;gpu_utilization_percent&quot;">​</a></h3><p>GPU 计算利用率。</p><p><strong>类型:</strong> Gauge</p><p><strong>标签:</strong> <code>vendor</code>, <code>gpu</code>, <code>name</code>, <code>uuid</code>, <code>device_id</code></p><p><strong>范围:</strong> 0-100</p><div class="language-promql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">promql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># GPU 利用率</span></span>
<span class="line"><span>gpu_utilization_percent{job=&quot;node&quot;}</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 利用率超过 90% 的 GPU</span></span>
<span class="line"><span>gpu_utilization_percent{job=&quot;node&quot;} &gt; 90</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 按实例统计平均利用率</span></span>
<span class="line"><span>avg by (instance) (gpu_utilization_percent{job=&quot;node&quot;})</span></span></code></pre></div><h2 id="显存指标" tabindex="-1">显存指标 <a class="header-anchor" href="#显存指标" aria-label="Permalink to &quot;显存指标&quot;">​</a></h2><h3 id="gpu-memory-used-percent" tabindex="-1">gpu_memory_used_percent <a class="header-anchor" href="#gpu-memory-used-percent" aria-label="Permalink to &quot;gpu_memory_used_percent&quot;">​</a></h3><p>GPU 显存使用率。</p><p><strong>类型:</strong> Gauge</p><p><strong>标签:</strong> <code>vendor</code>, <code>gpu</code>, <code>name</code>, <code>uuid</code>, <code>device_id</code></p><p><strong>范围:</strong> 0-100</p><div class="language-promql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">promql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># 显存使用率</span></span>
<span class="line"><span>gpu_memory_used_percent{job=&quot;node&quot;}</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 显存使用率超过 80%</span></span>
<span class="line"><span>gpu_memory_used_percent{job=&quot;node&quot;} &gt; 80</span></span></code></pre></div><h3 id="gpu-memory-used-bytes" tabindex="-1">gpu_memory_used_bytes <a class="header-anchor" href="#gpu-memory-used-bytes" aria-label="Permalink to &quot;gpu_memory_used_bytes&quot;">​</a></h3><p>已使用的 GPU 显存（字节）。</p><p><strong>类型:</strong> Gauge</p><p><strong>标签:</strong> 同上</p><div class="language-promql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">promql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># 已使用显存 (GB)</span></span>
<span class="line"><span>gpu_memory_used_bytes{job=&quot;node&quot;} / 1024 / 1024 / 1024</span></span></code></pre></div><h3 id="gpu-memory-total-bytes" tabindex="-1">gpu_memory_total_bytes <a class="header-anchor" href="#gpu-memory-total-bytes" aria-label="Permalink to &quot;gpu_memory_total_bytes&quot;">​</a></h3><p>GPU 显存总量（字节）。</p><p><strong>类型:</strong> Gauge</p><p><strong>标签:</strong> 同上</p><div class="language-promql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">promql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># 总显存 (GB)</span></span>
<span class="line"><span>gpu_memory_total_bytes{job=&quot;node&quot;} / 1024 / 1024 / 1024</span></span></code></pre></div><h2 id="功耗指标" tabindex="-1">功耗指标 <a class="header-anchor" href="#功耗指标" aria-label="Permalink to &quot;功耗指标&quot;">​</a></h2><h3 id="gpu-power-draw-watts" tabindex="-1">gpu_power_draw_watts <a class="header-anchor" href="#gpu-power-draw-watts" aria-label="Permalink to &quot;gpu_power_draw_watts&quot;">​</a></h3><p>GPU 当前功耗。</p><p><strong>类型:</strong> Gauge</p><p><strong>标签:</strong> <code>vendor</code>, <code>gpu</code>, <code>name</code>, <code>uuid</code>, <code>device_id</code></p><p><strong>单位:</strong> 瓦特 (W)</p><div class="language-promql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">promql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># GPU 当前功耗</span></span>
<span class="line"><span>gpu_power_draw_watts{job=&quot;node&quot;}</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 单实例 GPU 总功耗</span></span>
<span class="line"><span>sum by (instance) (gpu_power_draw_watts{job=&quot;node&quot;})</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 单实例平均单卡功耗</span></span>
<span class="line"><span>avg by (instance) (gpu_power_draw_watts{job=&quot;node&quot;})</span></span></code></pre></div><h2 id="nvidia-特有信息" tabindex="-1">NVIDIA 特有信息 <a class="header-anchor" href="#nvidia-特有信息" aria-label="Permalink to &quot;NVIDIA 特有信息&quot;">​</a></h2><p>NVIDIA GPU 会通过 <code>nvidia-smi</code> 获取以下额外信息：</p><table tabindex="0"><thead><tr><th>字段</th><th>说明</th><th>示例</th></tr></thead><tbody><tr><td><code>gpu</code></td><td>GPU 编号</td><td><code>0</code>, <code>1</code></td></tr><tr><td><code>name</code></td><td>GPU 型号名称</td><td><code>NVIDIA GeForce RTX 3090</code></td></tr><tr><td><code>uuid</code></td><td>GPU 唯一标识符</td><td><code>GPU-xxxx-xxxx-xxxx-xxxx</code></td></tr></tbody></table><h2 id="amd-rocm-特有信息" tabindex="-1">AMD ROCm 特有信息 <a class="header-anchor" href="#amd-rocm-特有信息" aria-label="Permalink to &quot;AMD ROCm 特有信息&quot;">​</a></h2><p>AMD GPU 会通过 <code>rocm-smi</code> 获取以下额外信息：</p><table tabindex="0"><thead><tr><th>字段</th><th>说明</th><th>示例</th></tr></thead><tbody><tr><td><code>gpu</code></td><td>GPU 编号</td><td><code>0</code>, <code>1</code></td></tr><tr><td><code>device_id</code></td><td>设备 ID</td><td><code>card0</code>, <code>card1</code></td></tr><tr><td><code>name</code></td><td>GPU 型号名称</td><td><code> Vega 10 [Radeon RX Vega 56/64]</code></td></tr></tbody></table><h2 id="查询示例" tabindex="-1">查询示例 <a class="header-anchor" href="#查询示例" aria-label="Permalink to &quot;查询示例&quot;">​</a></h2><h3 id="完整-gpu-状态仪表盘" tabindex="-1">完整 GPU 状态仪表盘 <a class="header-anchor" href="#完整-gpu-状态仪表盘" aria-label="Permalink to &quot;完整 GPU 状态仪表盘&quot;">​</a></h3><div class="language-promql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">promql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># GPU 基本信息</span></span>
<span class="line"><span>gpu_info{job=&quot;node&quot;}</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 温度 (着色显示)</span></span>
<span class="line"><span>gpu_temperature_celsius{job=&quot;node&quot;}</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 利用率 (百分比)</span></span>
<span class="line"><span>gpu_utilization_percent{job=&quot;node&quot;}</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 显存使用率</span></span>
<span class="line"><span>gpu_memory_used_percent{job=&quot;node&quot;}</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 功耗</span></span>
<span class="line"><span>gpu_power_draw_watts{job=&quot;node&quot;}</span></span></code></pre></div><h3 id="按实例汇总" tabindex="-1">按实例汇总 <a class="header-anchor" href="#按实例汇总" aria-label="Permalink to &quot;按实例汇总&quot;">​</a></h3><div class="language-promql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">promql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># 每台服务器的 GPU 数量</span></span>
<span class="line"><span>sum by (instance) (node_push_exporter_gpu_devices_detected{job=&quot;node&quot;})</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 每台服务器的平均 GPU 温度</span></span>
<span class="line"><span>avg by (instance) (gpu_temperature_celsius{job=&quot;node&quot;})</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 每台服务器的平均 GPU 利用率</span></span>
<span class="line"><span>avg by (instance) (gpu_utilization_percent{job=&quot;node&quot;})</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 每台服务器的总 GPU 功耗</span></span>
<span class="line"><span>sum by (instance) (gpu_power_draw_watts{job=&quot;node&quot;})</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 每台服务器的总显存使用</span></span>
<span class="line"><span>sum by (instance) (gpu_memory_used_bytes{job=&quot;node&quot;}) / 1024 / 1024 / 1024</span></span></code></pre></div><h3 id="按厂商分析" tabindex="-1">按厂商分析 <a class="header-anchor" href="#按厂商分析" aria-label="Permalink to &quot;按厂商分析&quot;">​</a></h3><div class="language-promql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">promql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># NVIDIA vs AMD GPU 分布</span></span>
<span class="line"><span>count by (vendor) (gpu_info{job=&quot;node&quot;})</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 各厂商平均温度</span></span>
<span class="line"><span>avg by (vendor) (gpu_temperature_celsius{job=&quot;node&quot;})</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 各厂商平均利用率</span></span>
<span class="line"><span>avg by (vendor) (gpu_utilization_percent{job=&quot;node&quot;})</span></span></code></pre></div><h2 id="故障排查" tabindex="-1">故障排查 <a class="header-anchor" href="#故障排查" aria-label="Permalink to &quot;故障排查&quot;">​</a></h2><h3 id="gpu-指标采集失败" tabindex="-1">GPU 指标采集失败 <a class="header-anchor" href="#gpu-指标采集失败" aria-label="Permalink to &quot;GPU 指标采集失败&quot;">​</a></h3><p>检查 <code>node_push_exporter_gpu_scrape_success</code>:</p><div class="language-promql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">promql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># 找出采集失败的 GPU</span></span>
<span class="line"><span>node_push_exporter_gpu_scrape_success{job=&quot;node&quot;} == 0</span></span></code></pre></div><p>可能原因：</p><ol><li>未安装对应驱动</li><li>nvidia-smi 或 rocm-smi 不在 PATH 中</li><li>无 GPU 设备</li><li>权限不足</li></ol><h3 id="gpu-设备数为-0" tabindex="-1">GPU 设备数为 0 <a class="header-anchor" href="#gpu-设备数为-0" aria-label="Permalink to &quot;GPU 设备数为 0&quot;">​</a></h3><div class="language-promql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">promql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># 检查是否有设备</span></span>
<span class="line"><span>node_push_exporter_gpu_devices_detected{job=&quot;node&quot;} == 0</span></span></code></pre></div><p>可能原因：</p><ol><li>系统没有 GPU</li><li>GPU 驱动未加载</li><li>虚拟化环境未穿透 GPU</li></ol>`,107)])])}const g=e(p,[["render",o]]);export{h as __pageData,g as default};
